const faviconChunks = [
  "",
  "",
  "",
  "",
  "",
  "",
  "",
  ""
];

const faviconData = `data:image/png;base64,${faviconChunks.join("")}`;

function ensureLink(id, rel, type) {
  let link = document.getElementById(id);
  if (!link) {
    link = document.createElement("link");
    link.id = id;
    link.rel = rel;
    if (type) link.type = type;
    document.head.appendChild(link);
  }

  return link;
}

function applyFavicon() {
  const faviconLink = ensureLink("site-favicon", "icon", "image/png");
  const shortcutIconLink = ensureLink("site-shortcut-icon", "shortcut icon");
  const appleTouchIconLink = ensureLink("site-apple-touch-icon", "apple-touch-icon");

  faviconLink.href = faviconData;
  shortcutIconLink.href = faviconData;
  appleTouchIconLink.href = faviconData;
}

applyFavicon();
document.addEventListener("DOMContentLoaded", applyFavicon);
window.addEventListener("load", applyFavicon);
setTimeout(applyFavicon, 150);
